-- Department Risk Analysis After Model Scoring
-- Purpose:
--   Summarize model risk concentration by department using the scored employee
--   table generated by the Python pipeline.
--
-- Expected table:
--   employee_attrition_risk_scores

WITH scored AS (
    SELECT
        Department,
        JobRole,
        EmployeeNumber,
        Attrition,
        attrition_flag,
        attrition_probability,
        risk_decile,
        risk_band,
        CASE WHEN risk_decile <= 2 THEN 1 ELSE 0 END AS top_20_risk_flag,
        CASE WHEN risk_decile <= 3 THEN 1 ELSE 0 END AS top_30_risk_flag
    FROM employee_attrition_risk_scores
),
department_summary AS (
    SELECT
        Department,
        COUNT(*) AS employees,
        SUM(attrition_flag) AS observed_attrition_count,
        AVG(attrition_flag * 1.0) AS observed_attrition_rate,
        AVG(attrition_probability) AS mean_attrition_probability,
        MAX(attrition_probability) AS max_attrition_probability,
        AVG(top_20_risk_flag * 1.0) AS top_20_risk_share,
        AVG(top_30_risk_flag * 1.0) AS top_30_risk_share
    FROM scored
    GROUP BY Department
),
role_mix AS (
    SELECT
        Department,
        JobRole,
        COUNT(*) AS employees,
        AVG(attrition_probability) AS mean_role_probability,
        ROW_NUMBER() OVER (
            PARTITION BY Department
            ORDER BY AVG(attrition_probability) DESC, COUNT(*) DESC
        ) AS role_rank
    FROM scored
    GROUP BY Department, JobRole
)
SELECT
    d.Department,
    d.employees,
    d.observed_attrition_count,
    d.observed_attrition_rate,
    d.mean_attrition_probability,
    d.max_attrition_probability,
    d.top_20_risk_share,
    d.top_30_risk_share,
    r.JobRole AS highest_risk_role,
    r.mean_role_probability AS highest_risk_role_probability,
    CASE
        WHEN d.top_20_risk_share >= 0.30 THEN 'prioritize department-level retention review'
        WHEN d.mean_attrition_probability >= 0.25 THEN 'monitor department risk signals'
        ELSE 'standard monitoring'
    END AS recommended_review_posture
FROM department_summary d
LEFT JOIN role_mix r
    ON d.Department = r.Department
   AND r.role_rank = 1
ORDER BY d.mean_attrition_probability DESC;